import{_ as t,o as a,c as r,ae as o}from"./chunks/framework.N7L1bt_W.js";const u=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),s={name:"guide/introduction.md"};function n(i,e,d,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><strong>OWL-SDA</strong> (OWL Synthetic Data AI-Agent) is a Java tool that generates synthetic RDF instance data from OWL ontologies using Large Language Models (LLMs).</p><p>Given an input ontology (in Turtle or RDF/XML format) and a natural-language prompt describing the desired data, OWL-SDA:</p><ol><li>Loads and optionally reasons over the ontology (including fetching external imports).</li><li>Derives SHACL shapes from the OWL class descriptions.</li><li>Dispatches a <strong>supervisor</strong> agent that coordinates a pool of <strong>worker</strong> agents, each responsible for generating instances for a subset of SHACL shapes.</li><li>Validates the generated triples against the SHACL shapes after each round.</li><li>Passes the final output to a <strong>reviewer</strong> agent that either accepts it or requests targeted revisions.</li></ol><h2 id="key-concepts" tabindex="-1">Key Concepts <a class="header-anchor" href="#key-concepts" aria-label="Permalink to &quot;Key Concepts&quot;">​</a></h2><h3 id="agents" tabindex="-1">Agents <a class="header-anchor" href="#agents" aria-label="Permalink to &quot;Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Role</th><th>Responsibility</th></tr></thead><tbody><tr><td><strong>Supervisor</strong></td><td>Orchestrates the generation loop, assigns shapes to workers, and finalises the output.</td></tr><tr><td><strong>Worker (pool)</strong></td><td>Generates RDF triples for its assigned shapes and writes them to the shared triple store.</td></tr><tr><td><strong>Reviewer</strong></td><td>Reviews the fully assembled output and signals ACCEPTED, REJECTED, or REVISION_REQUESTED.</td></tr></tbody></table><h3 id="shacl-shapes" tabindex="-1">SHACL Shapes <a class="header-anchor" href="#shacl-shapes" aria-label="Permalink to &quot;SHACL Shapes&quot;">​</a></h3><p>OWL-SDA automatically generates <a href="https://www.w3.org/TR/shacl/" target="_blank" rel="noreferrer">SHACL</a> NodeShapes from <code>owl:Class</code> definitions, including property shapes derived from <code>owl:Restriction</code> axioms. These shapes are used both to guide the workers and to validate the output after each generation round.</p><h3 id="triple-store" tabindex="-1">Triple Store <a class="header-anchor" href="#triple-store" aria-label="Permalink to &quot;Triple Store&quot;">​</a></h3><p>Workers write triples directly into a shared in-memory triple store. After each delegation round the store is flushed to the configured output file so that the supervisor and reviewer can read it.</p><h2 id="supported-llm-backends" tabindex="-1">Supported LLM Backends <a class="header-anchor" href="#supported-llm-backends" aria-label="Permalink to &quot;Supported LLM Backends&quot;">​</a></h2><p>Currently only <strong>GitHub Copilot</strong> is supported as a language model backend. Support for additional providers can be added by implementing the <code>Client</code> / <code>Session</code> interfaces.</p><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>OWL-SDA is distributed under the <strong>GNU General Public License v3.0</strong>. See <a href="./license.html">License</a> for details and the full license text.</p>',15)])])}const g=t(s,[["render",n]]);export{u as __pageData,g as default};
